#include "core.h"
#include "music.h"
#include "sim.h"
#include <math.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main(int argc,char**argv){int count=argc>1?atoi(argv[1]):100000,bad=0;uint64_t digest=1469598103934665603ULL;for(int i=0;i<count;i++){char seed[7];sfbs_random_seed(0x51a7ULL+(uint64_t)i,seed);Genome g=sfbs_genome(seed);GameMode mode=(GameMode)(i%3);Phrase p[SFBS_PHRASES];sfbs_phrases(&g,mode,p);Song s;sfbs_song_generate(&g,p,&s);if(!sfbs_song_valid(&s)||s.count>SFBS_EVENTS)bad++;if(g.music_seed==g.layout_seed||g.music_seed==g.gameplay_seed||g.music_seed==g.visual_seed||g.layout_seed==g.gameplay_seed||g.layout_seed==g.visual_seed||g.gameplay_seed==g.visual_seed)bad++;for(int j=0;j<SFBS_PHRASES;j++){Pattern q=p[j].pattern;if(sfbs_popcount(q.bits)!=q.pulses||q.steps<8||q.steps>16||q.pulses<1||q.pulses>=q.steps||p[j].ring>2||p[j].start_bar!=j*4||p[j].bars!=4)bad++;float radius=(float[]){105,190,270}[p[j].ring];float minimum=2*radius*sinf(SFBS_PI/q.steps);if(radius>270.01f||radius<105||minimum<16)bad++;if(j>0&&j<12){float before=p[j-1].pattern.pulses/(float)p[j-1].pattern.steps,after=q.pulses/(float)q.steps;if(after>before*1.351f)bad++;if(q.bits==p[j-1].pattern.bits&&q.steps==p[j-1].pattern.steps)bad++;}}if(p[12].phase!=PH_FINAL||p[13].phase!=PH_FINAL||p[12].pattern.pulses<6||p[13].pattern.pulses<8)bad++;for(int e=0;e<s.count;e++){const MusicEvent*x=&s.events[e];if(x->note<20||x->note>110||x->stem>3||x->voice>5||(e&&x->sample<s.events[e-1].sample))bad++;}digest^=g.master+(uint64_t)s.count;digest*=1099511628211ULL;}printf("validated=%d failures=%d digest=%016llx\n",count,bad,(unsigned long long)digest);return bad?1:0;}
